import { g as createComponent, m as maybeRenderHead, u as unescapeHTML, r as renderTemplate } from './astro/server_mSrCIW4D.mjs';
import 'kleur/colors';
import 'clsx';

const html = "<p>图（Graph）是计算机科学中最强大、最复杂，也是 ACM/ICPC 竞赛中考察频率最高的数据结构之一。无论是社交网络的好友推荐，还是地图导航的最短路径，背后都离不开图论的支持。</p>\n<p>本文将用最通俗易懂的语言，带你系统梳理图论的核心知识体系。</p>\n<h2 id=\"1-图的基本概念到底什么是图\">1. 图的基本概念：到底什么是图？</h2>\n<p>别被“图论”这个高大上的名字吓到了。<strong>图</strong>其实就是用来描述“<strong>关系</strong>”的。</p>\n<p>想象一下微信好友列表：</p>\n<ul>\n<li><strong>顶点 (Vertex)</strong>：就是你和你的朋友们。</li>\n<li><strong>边 (Edge)</strong>：就是你们之间的“好友关系”。</li>\n</ul>\n<p>我们可以把图看作是从 <strong>链表</strong>（一条线）和 <strong>树</strong>（分叉的树枝）拓展而来的更自由的<strong>网络</strong>。</p>\n<h3 id=\"常见的分类\">常见的分类</h3>\n<ol>\n<li>\n<p><strong>无向图 vs 有向图</strong>：</p>\n<ul>\n<li><strong>无向图</strong>：双向奔赴。比如微信好友，我加了你，你也就加了我。A 和 B 是平等的。</li>\n<li><strong>有向图</strong>：单相思。比如微博关注，我关注了明星，明星不一定关注我。箭头是有方向的 (A -> B)。</li>\n</ul>\n</li>\n<li>\n<p><strong>无权图 vs 有权图</strong>：</p>\n<ul>\n<li><strong>有权图</strong>：关系有“分量”。比如地图上两个城市之间，不仅连通，还有<strong>距离</strong>（权重）。或者两个人之间不仅认识，还有<strong>亲密度</strong>（权重）。</li>\n</ul>\n</li>\n<li>\n<p><strong>连通图 vs 非连通图</strong>：</p>\n<ul>\n<li><strong>连通图</strong>：从任何一个点出发，都能走到其他任何一个点。</li>\n<li><strong>非连通图</strong>：像几座孤岛，岛与岛之间没有桥。</li>\n</ul>\n</li>\n</ol>\n<h3 id=\"核心术语\">核心术语</h3>\n<ul>\n<li><strong>度 (Degree)</strong>：一个点连了几条线。\n<ul>\n<li>在有向图中，<strong>入度</strong>是谁指向我，<strong>出度</strong>是我指向谁。</li>\n</ul>\n</li>\n<li><strong>路径 (Path)</strong>：从起点走到终点经过的路线。</li>\n</ul>\n<hr>\n<h2 id=\"2-图的存储怎么把图塞进代码里\">2. 图的存储：怎么把图塞进代码里？</h2>\n<p>在 ACM 竞赛中，选对存图方式至关重要。选错了，要么代码写死人，要么内存爆掉。</p>\n<h3 id=\"21-邻接矩阵-adjacency-matrix--简单粗暴的二维数组\">2.1 邻接矩阵 (Adjacency Matrix) —— 简单粗暴的二维数组</h3>\n<p>想象一个表格，行是起点，列是终点。表格里的数字表示有没有边（或者权重）。</p>\n<ul>\n<li><strong>特点</strong>：简单直观。<code>g[i][j] = 1</code> 表示 i 和 j 连通。</li>\n<li><strong>优点</strong>：查得快！想知道 i 和 j 连不连？直接看表格。</li>\n<li><strong>缺点</strong>：太费地儿！如果有 10000 个点，就要开 <code>10000 * 10000</code> 的数组，内存直接爆炸。</li>\n<li><strong>适用</strong>：点很少的图（点数 N &#x3C;= 1000）。</li>\n</ul>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#6A737D\">// C++ 邻接矩阵示例</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">const</span><span style=\"color:#F97583\"> int</span><span style=\"color:#E1E4E8\"> INF </span><span style=\"color:#F97583\">=</span><span style=\"color:#F97583\"> 0x</span><span style=\"color:#79B8FF\">3f3f3f3f</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> g[</span><span style=\"color:#79B8FF\">1005</span><span style=\"color:#E1E4E8\">][</span><span style=\"color:#79B8FF\">1005</span><span style=\"color:#E1E4E8\">];</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> init</span><span style=\"color:#E1E4E8\">() {</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 刚开始谁都不挨着谁</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(g, </span><span style=\"color:#F97583\">0x</span><span style=\"color:#79B8FF\">3f</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(g));</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> add_edge</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> v</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> w</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    g[u][v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> w;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    g[v][u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> w;</span><span style=\"color:#6A737D\"> // 无向图记得反过来也要存一下</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"22-邻接表-adjacency-list--也就是-vector\">2.2 邻接表 (Adjacency List) —— 也就是 Vector</h3>\n<p>每个点都有一个小本本（Vector），上面记着它连着谁。</p>\n<ul>\n<li><strong>特点</strong>：按需分配。只存存在的边，省内存。</li>\n<li><strong>优点</strong>：空间利用率高，大部分题目都用它。</li>\n<li><strong>缺点</strong>：想知道 i 和 j 连不连？得翻 i 的小本本，稍微慢一点点。</li>\n</ul>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#6A737D\">// C++ vector 实现邻接表</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">struct</span><span style=\"color:#B392F0\"> Edge</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> to;</span><span style=\"color:#6A737D\">     // 连到谁</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> weight;</span><span style=\"color:#6A737D\"> // 权重多少</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">};</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">vector</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\">Edge</span><span style=\"color:#F97583\">></span><span style=\"color:#E1E4E8\"> adj[</span><span style=\"color:#79B8FF\">100005</span><span style=\"color:#E1E4E8\">];</span><span style=\"color:#6A737D\"> // 每个点都有一个 vector</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> add_edge</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> v</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> w</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    adj[u].</span><span style=\"color:#B392F0\">push_back</span><span style=\"color:#E1E4E8\">({v, w});</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 无向图加上这一句: adj[v].push_back({u, w});</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"23-链式前向星-chain-forward-star--数组模拟链表高手必备\">2.3 链式前向星 (Chain Forward Star) —— 数组模拟链表（高手必备）</h3>\n<p>这是 ACM 选手最爱用的存图方式，虽然名字听起来很中二，但效率极高！</p>\n<p>它的本质是<strong>用数组来模拟链表</strong>。为什么不用 Vector？因为 Vector 动态扩容有点慢，而数组是静态的，快！</p>\n<p><strong>想象一下：</strong>\n你要寄信（边）。</p>\n<ul>\n<li><code>head[u]</code>：你（点 u）寄出的<strong>第一封信</strong>的编号。</li>\n<li><code>next[e]</code>：信 e 下面压着的<strong>下一封信</strong>的编号。</li>\n<li><code>to[e]</code>：信 e 是寄给谁的。</li>\n<li><code>val[e]</code>：信 e 的权重。</li>\n</ul>\n<p><strong>插入边的时候（头插法）：</strong>\n每次有新边，都把它插到最前面，变成新的“第一封信”，然后让它指向原来的“第一封信”。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#6A737D\">// 链式前向星模板</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">const</span><span style=\"color:#F97583\"> int</span><span style=\"color:#E1E4E8\"> N </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 100005</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\">  // 最大点数</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">const</span><span style=\"color:#F97583\"> int</span><span style=\"color:#E1E4E8\"> M </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 200005</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\">  // 最大边数</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> head[N];</span><span style=\"color:#6A737D\"> // 存储每个点的第一条边的索引，初始化为 -1</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">struct</span><span style=\"color:#B392F0\"> Edge</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> to;</span><span style=\"color:#6A737D\">   // 这条边去哪</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> next;</span><span style=\"color:#6A737D\"> // 下一条同起点的边在哪</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> w;</span><span style=\"color:#6A737D\">    // 权重</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">} edges[M];</span><span style=\"color:#6A737D\">   // 边集数组</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> cnt </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 边的计数器</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 初始化</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> init</span><span style=\"color:#E1E4E8\">() {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(head, </span><span style=\"color:#F97583\">-</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(head));</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    cnt </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 加边函数：把 u -> v，权重 w 的边加入</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> add</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> v</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> w</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    edges[cnt].to </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> v;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    edges[cnt].w </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> w;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    edges[cnt].next </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> head[u];</span><span style=\"color:#6A737D\"> // 新边的下一条指向原本的第一条（头插法）</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    head[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> cnt;</span><span style=\"color:#6A737D\">             // 更新 u 的第一条边为当前新边</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    cnt</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 遍历 u 的所有出边</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> traverse</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // i = head[u] 开始，只要 i != -1 就继续，每次跳到 next[i]</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> i </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> head[u]; i </span><span style=\"color:#F97583\">!=</span><span style=\"color:#F97583\"> -</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">; i </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edges[i].next) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edges[i].to;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> w </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edges[i].w;</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">        // 这里处理边 (u, v)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        cout </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#9ECBFF\"> \"从 \"</span><span style=\"color:#F97583\"> &#x3C;&#x3C;</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#9ECBFF\"> \" 到 \"</span><span style=\"color:#F97583\"> &#x3C;&#x3C;</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#9ECBFF\"> \" 权重 \"</span><span style=\"color:#F97583\"> &#x3C;&#x3C;</span><span style=\"color:#E1E4E8\"> w </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#E1E4E8\"> endl;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<p><strong>为什么叫“前向星”？</strong> 因为它是从某个点出发，像星星的光芒一样向前（Forward）发散出去。虽然代码稍显复杂，但<strong>速度最快</strong>，<strong>内存最省</strong>，是打比赛的终极武器。</p>\n<hr>\n<h2 id=\"3-图的遍历怎么在图里溜达\">3. 图的遍历：怎么在图里溜达？</h2>\n<p>有了图，我们得进去走走。</p>\n<h3 id=\"31-深度优先搜索-dfs--钻牛角尖\">3.1 深度优先搜索 (DFS) —— 钻牛角尖</h3>\n<p><strong>口诀</strong>：“不撞南墙不回头”。\n一条路走到黑，走不通了再退回来换条路走。</p>\n<p><strong>用途</strong>：</p>\n<ul>\n<li>走迷宫（找能不能走通）。</li>\n<li>全排列（把所有可能性都试一遍）。</li>\n</ul>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#E1E4E8\"> vis[</span><span style=\"color:#79B8FF\">100005</span><span style=\"color:#E1E4E8\">];</span><span style=\"color:#6A737D\"> // 记录走没走过，防止转圈圈</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> dfs</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    vis[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 标记：我来过啦</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 遍历 u 的所有邻居</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> edge : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.to;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">vis[v]) {</span><span style=\"color:#6A737D\"> // 如果邻居没去过</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">            dfs</span><span style=\"color:#E1E4E8\">(v);</span><span style=\"color:#6A737D\">    // 接着往下钻</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"32-广度优先搜索-bfs--地毯式搜索\">3.2 广度优先搜索 (BFS) —— 地毯式搜索</h3>\n<p><strong>口诀</strong>：“层层递进”。\n先把离我最近的一圈全走完，再走第二圈。</p>\n<p><strong>用途</strong>：</p>\n<ul>\n<li><strong>找最短路径</strong>（仅限边权为 1 的图）。比如游戏里找最近的怪。</li>\n</ul>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> bfs</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> start</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    queue</span><span style=\"color:#F97583\">&#x3C;int></span><span style=\"color:#E1E4E8\"> q;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(start);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    vis[start] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    while</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">q.</span><span style=\"color:#B392F0\">empty</span><span style=\"color:#E1E4E8\">()) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> q.</span><span style=\"color:#B392F0\">front</span><span style=\"color:#E1E4E8\">(); q.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span><span style=\"color:#6A737D\"> // 取出队头</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> edge : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.to;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">vis[v]) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                vis[v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 标记</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(v);</span><span style=\"color:#6A737D\">     // 加入队列，以后再处理</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<hr>\n<h2 id=\"4-经典算法实战伪代码\">4. 经典算法实战（伪代码）</h2>\n<p>光说不练假把式。这里给出 ACM 竞赛中最常用的核心算法模板，<strong>建议背诵全文</strong>！</p>\n<h3 id=\"41-最短路径算法\">4.1 最短路径算法</h3>\n<h4 id=\"1-dijkstra-算法--正权图的最短路之王\">(1) Dijkstra 算法 —— 正权图的最短路之王</h4>\n<p><strong>适用</strong>：没有负权边的图。</p>\n<p><strong>核心思想</strong>：贪心。每次从未被标记的点中，找到距离起点最近的那个点 <code>u</code>，然后用 <code>u</code> 去更新它的邻居们。</p>\n<p><strong>生活比喻</strong>：你想去学校，先看看离家最近的车站 A 有多远，到了 A 之后，再看看通过 A 去其他地方会不会更近。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#6A737D\">// 堆优化 Dijkstra (复杂度 O(E log E))</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// dis[i] 存储起点到 i 的最短距离</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> dis[N];</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#E1E4E8\"> vis[N];</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">// 小根堆，自动按距离从小到大排序</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">priority_queue</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\">pair</span><span style=\"color:#F97583\">&#x3C;int</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int></span><span style=\"color:#E1E4E8\">, vector</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\">pair</span><span style=\"color:#F97583\">&#x3C;int</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int>></span><span style=\"color:#E1E4E8\">, greater</span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\">pair</span><span style=\"color:#F97583\">&#x3C;int</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int>>></span><span style=\"color:#E1E4E8\"> pq;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> dijkstra</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> start</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(dis, </span><span style=\"color:#F97583\">0x</span><span style=\"color:#79B8FF\">3f</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(dis));</span><span style=\"color:#6A737D\"> // 初始化无穷大</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    dis[start] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    pq.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">({</span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">, start});</span><span style=\"color:#6A737D\"> // {距离, 点编号}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    while</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">pq.</span><span style=\"color:#B392F0\">empty</span><span style=\"color:#E1E4E8\">()) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> pq.</span><span style=\"color:#B392F0\">top</span><span style=\"color:#E1E4E8\">().second;</span><span style=\"color:#6A737D\"> // 拿出距离最近的点</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        pq.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (vis[u]) </span><span style=\"color:#F97583\">continue</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 如果处理过了就跳过</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        vis[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> edge : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.to;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> w </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.w;</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">            // 松弛操作：如果通过 u 走到 v 更近</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (dis[v] </span><span style=\"color:#F97583\">></span><span style=\"color:#E1E4E8\"> dis[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#E1E4E8\"> w) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                dis[v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> dis[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#E1E4E8\"> w;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                pq.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">({dis[v], v});</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h4 id=\"2-spfa-算法--负权边的克星\">(2) SPFA 算法 —— 负权边的克星</h4>\n<p><strong>适用</strong>：存在负权边，但没有负环的图。</p>\n<p><strong>核心思想</strong>：队列优化的 Bellman-Ford。只有当一个点的最短距离变小了，它才可能去更新它的邻居，所以把它加入队列。</p>\n<p><strong>注意</strong>：在网格图或构造数据中容易退化成 <code>O(VE)</code>，比赛时慎用（除非有负权边）。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#E1E4E8\"> in_queue[N];</span><span style=\"color:#6A737D\"> // 记录是否在队列中</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> spfa</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> start</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(dis, </span><span style=\"color:#F97583\">0x</span><span style=\"color:#79B8FF\">3f</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(dis));</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    dis[start] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    queue</span><span style=\"color:#F97583\">&#x3C;int></span><span style=\"color:#E1E4E8\"> q;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(start);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    in_queue[start] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    while</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">q.</span><span style=\"color:#B392F0\">empty</span><span style=\"color:#E1E4E8\">()) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> q.</span><span style=\"color:#B392F0\">front</span><span style=\"color:#E1E4E8\">(); q.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        in_queue[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> false</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 出队</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> edge : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.to;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> w </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.w;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (dis[v] </span><span style=\"color:#F97583\">></span><span style=\"color:#E1E4E8\"> dis[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#E1E4E8\"> w) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                dis[v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> dis[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#E1E4E8\"> w;</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">                // 如果 v 已经在队列里，就不用重复加了</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">                if</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">in_queue[v]) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                    q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(v);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                    in_queue[v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h4 id=\"3-floyd-warshall-算法--多源最短路\">(3) Floyd-Warshall 算法 —— 多源最短路</h4>\n<p><strong>适用</strong>：求任意两点间的最短路，点数 <code>N &#x3C;= 300</code>。</p>\n<p><strong>核心思想</strong>：动态规划。对于每一对 <code>(i, j)</code>，看看能不能找个中间商 <code>k</code>，使得 <code>i -> k -> j</code> 比直接 <code>i -> j</code> 更短。</p>\n<p><strong>记忆口诀</strong>：<strong>“中间商 k 在最外层”</strong>。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#6A737D\">// dp[i][j] 表示 i 到 j 的最短距离</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> floyd</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> n</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // k 必须在最外层循环！</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> k </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; k </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; k</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> i </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; i </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; i</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> j </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; j </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; j</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                dp[i][j] </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> min</span><span style=\"color:#E1E4E8\">(dp[i][j], dp[i][k] </span><span style=\"color:#F97583\">+</span><span style=\"color:#E1E4E8\"> dp[k][j]);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"42-最小生成树-mst\">4.2 最小生成树 (MST)</h3>\n<h4 id=\"1-kruskal-算法--加边法\">(1) Kruskal 算法 —— 加边法</h4>\n<p><strong>适用</strong>：稀疏图（边少）。</p>\n<p><strong>核心思想</strong>：贪心。把所有路按造价从小到大排序，选最便宜且不构成环的路（用并查集维护）。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">struct</span><span style=\"color:#B392F0\"> Edge</span><span style=\"color:#E1E4E8\"> { </span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> u, v, w; };</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#B392F0\"> cmp</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#B392F0\">Edge</span><span style=\"color:#FFAB70\"> a</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">Edge</span><span style=\"color:#FFAB70\"> b</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#F97583\">return</span><span style=\"color:#E1E4E8\"> a.w </span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\"> b.w; }</span><span style=\"color:#6A737D\"> // 按权重排序</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> fa[N];</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#B392F0\"> find</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> x</span><span style=\"color:#E1E4E8\">) { </span><span style=\"color:#F97583\">return</span><span style=\"color:#E1E4E8\"> fa[x] </span><span style=\"color:#F97583\">==</span><span style=\"color:#E1E4E8\"> x </span><span style=\"color:#F97583\">?</span><span style=\"color:#E1E4E8\"> x </span><span style=\"color:#F97583\">:</span><span style=\"color:#E1E4E8\"> fa[x] </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> find</span><span style=\"color:#E1E4E8\">(fa[x]); }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> kruskal</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> n</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#B392F0\">vector</span><span style=\"color:#E1E4E8\">&#x3C;</span><span style=\"color:#B392F0\">Edge</span><span style=\"color:#E1E4E8\">></span><span style=\"color:#F97583\">&#x26;</span><span style=\"color:#FFAB70\"> edges</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    sort</span><span style=\"color:#E1E4E8\">(edges.</span><span style=\"color:#B392F0\">begin</span><span style=\"color:#E1E4E8\">(), edges.</span><span style=\"color:#B392F0\">end</span><span style=\"color:#E1E4E8\">(), cmp);</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> i </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; i </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; i</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) fa[i] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> i;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> count </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">, total_weight </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> e : edges) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> root_u </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> find</span><span style=\"color:#E1E4E8\">(e.u);</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> root_v </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> find</span><span style=\"color:#E1E4E8\">(e.v);</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (root_u </span><span style=\"color:#F97583\">!=</span><span style=\"color:#E1E4E8\"> root_v) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            fa[root_u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> root_v;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            total_weight </span><span style=\"color:#F97583\">+=</span><span style=\"color:#E1E4E8\"> e.w;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            count</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (count </span><span style=\"color:#F97583\">==</span><span style=\"color:#E1E4E8\"> n </span><span style=\"color:#F97583\">-</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">) </span><span style=\"color:#F97583\">break</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h4 id=\"2-prim-算法--加点法\">(2) Prim 算法 —— 加点法</h4>\n<p><strong>适用</strong>：稠密图（边多）。</p>\n<p><strong>核心思想</strong>：类似 Dijkstra。每次寻找距离“当前生成树”最近的那个点，把它加入集合。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> dist[N];</span><span style=\"color:#6A737D\"> // 点到生成树的最小距离</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#E1E4E8\"> vis[N];</span><span style=\"color:#6A737D\"> // 是否已加入生成树</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#B392F0\"> prim</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> n</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(dist, </span><span style=\"color:#F97583\">0x</span><span style=\"color:#79B8FF\">3f</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(dist));</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    int</span><span style=\"color:#E1E4E8\"> res </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    dist[</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">;</span><span style=\"color:#6A737D\"> // 从点 1 开始</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> i </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">; i </span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\"> n; i</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> t </span><span style=\"color:#F97583\">=</span><span style=\"color:#F97583\"> -</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">        // 寻找离集合最近的点</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> j </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; j </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; j</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">vis[j] </span><span style=\"color:#F97583\">&#x26;&#x26;</span><span style=\"color:#E1E4E8\"> (t </span><span style=\"color:#F97583\">==</span><span style=\"color:#F97583\"> -</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#F97583\"> ||</span><span style=\"color:#E1E4E8\"> dist[j] </span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\"> dist[t]))</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                t </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> j;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (i </span><span style=\"color:#F97583\">&#x26;&#x26;</span><span style=\"color:#E1E4E8\"> dist[t] </span><span style=\"color:#F97583\">==</span><span style=\"color:#E1E4E8\"> INF) </span><span style=\"color:#F97583\">return</span><span style=\"color:#E1E4E8\"> INF;</span><span style=\"color:#6A737D\"> // 图不连通</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (i) res </span><span style=\"color:#F97583\">+=</span><span style=\"color:#E1E4E8\"> dist[t];</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        vis[t] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">        // 用这个新点去更新其他点到集合的距离</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> j </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; j </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; j</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            dist[j] </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> min</span><span style=\"color:#E1E4E8\">(dist[j], g[t][j]);</span><span style=\"color:#6A737D\"> // g 是邻接矩阵</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    return</span><span style=\"color:#E1E4E8\"> res;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"43-图的连通性\">4.3 图的连通性</h3>\n<h4 id=\"tarjan-算法--强连通分量-scc\">Tarjan 算法 —— 强连通分量 (SCC)</h4>\n<p><strong>适用</strong>：有向图缩点。</p>\n<p><strong>核心思想</strong>：DFS 序 + 追溯值。如果一个点走了一圈能回到自己（或祖先），说明有个环。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> dfn[N], low[N], timestamp;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">stack</span><span style=\"color:#F97583\">&#x3C;int></span><span style=\"color:#E1E4E8\"> stk;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">bool</span><span style=\"color:#E1E4E8\"> in_stk[N];</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> scc_cnt, id[N];</span><span style=\"color:#6A737D\"> // 强连通分量编号</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> tarjan</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> u</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    dfn[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> low[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#F97583\"> ++</span><span style=\"color:#E1E4E8\">timestamp;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    stk.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(u); in_stk[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> true</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> v : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">dfn[v]) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">            tarjan</span><span style=\"color:#E1E4E8\">(v);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            low[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> min</span><span style=\"color:#E1E4E8\">(low[u], low[v]);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        } </span><span style=\"color:#F97583\">else</span><span style=\"color:#F97583\"> if</span><span style=\"color:#E1E4E8\"> (in_stk[v]) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            low[u] </span><span style=\"color:#F97583\">=</span><span style=\"color:#B392F0\"> min</span><span style=\"color:#E1E4E8\">(low[u], dfn[v]);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 找到一个 SCC 的根</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    if</span><span style=\"color:#E1E4E8\"> (dfn[u] </span><span style=\"color:#F97583\">==</span><span style=\"color:#E1E4E8\"> low[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        scc_cnt</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> y;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        do</span><span style=\"color:#E1E4E8\"> {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            y </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> stk.</span><span style=\"color:#B392F0\">top</span><span style=\"color:#E1E4E8\">(); stk.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            in_stk[y] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> false</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            id[y] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> scc_cnt;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        } </span><span style=\"color:#F97583\">while</span><span style=\"color:#E1E4E8\"> (y </span><span style=\"color:#F97583\">!=</span><span style=\"color:#E1E4E8\"> u);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"44-最近公共祖先-lca\">4.4 最近公共祖先 (LCA)</h3>\n<h4 id=\"倍增法\">倍增法</h4>\n<p><strong>核心思想</strong>：预处理出每个节点的第 $2^i$ 个祖先。查询时，先让深度深的跳到同一层，然后一起向上跳。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> fa[N][</span><span style=\"color:#79B8FF\">20</span><span style=\"color:#E1E4E8\">], depth[N];</span><span style=\"color:#6A737D\"> // fa[u][i] 表示 u 向上跳 2^i 步的祖先</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> bfs_lca</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> root</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#B392F0\">    memset</span><span style=\"color:#E1E4E8\">(depth, </span><span style=\"color:#F97583\">0x</span><span style=\"color:#79B8FF\">3f</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">sizeof</span><span style=\"color:#E1E4E8\">(depth));</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    depth[</span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">; depth[root] </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    queue</span><span style=\"color:#F97583\">&#x3C;int></span><span style=\"color:#E1E4E8\"> q; q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(root);</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    while</span><span style=\"color:#E1E4E8\"> (q.</span><span style=\"color:#B392F0\">size</span><span style=\"color:#E1E4E8\">()) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> q.</span><span style=\"color:#B392F0\">front</span><span style=\"color:#E1E4E8\">(); q.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> v : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (depth[v] </span><span style=\"color:#F97583\">></span><span style=\"color:#E1E4E8\"> depth[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                depth[v] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> depth[u] </span><span style=\"color:#F97583\">+</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(v);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                fa[v][</span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> u;</span><span style=\"color:#6A737D\"> // 跳 2^0 = 1 步就是父节点</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">                for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> k </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; k </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#79B8FF\"> 15</span><span style=\"color:#E1E4E8\">; k</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">                    fa[v][k] </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> fa[fa[v][k</span><span style=\"color:#F97583\">-</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">]][k</span><span style=\"color:#F97583\">-</span><span style=\"color:#79B8FF\">1</span><span style=\"color:#E1E4E8\">];</span><span style=\"color:#6A737D\"> // 2^k = 2^(k-1) + 2^(k-1)</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#B392F0\"> lca</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> a</span><span style=\"color:#E1E4E8\">, </span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> b</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    if</span><span style=\"color:#E1E4E8\"> (depth[a] </span><span style=\"color:#F97583\">&#x3C;</span><span style=\"color:#E1E4E8\"> depth[b]) </span><span style=\"color:#B392F0\">swap</span><span style=\"color:#E1E4E8\">(a, b);</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 先把 a 跳到和 b 同一层</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> k </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 15</span><span style=\"color:#E1E4E8\">; k </span><span style=\"color:#F97583\">>=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">; k</span><span style=\"color:#F97583\">--</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (depth[fa[a][k]] </span><span style=\"color:#F97583\">>=</span><span style=\"color:#E1E4E8\"> depth[b])</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            a </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> fa[a][k];</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    if</span><span style=\"color:#E1E4E8\"> (a </span><span style=\"color:#F97583\">==</span><span style=\"color:#E1E4E8\"> b) </span><span style=\"color:#F97583\">return</span><span style=\"color:#E1E4E8\"> a;</span></span>\n<span class=\"line\"><span style=\"color:#6A737D\">    // 一起向上跳，直到父亲相同</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> k </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 15</span><span style=\"color:#E1E4E8\">; k </span><span style=\"color:#F97583\">>=</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">; k</span><span style=\"color:#F97583\">--</span><span style=\"color:#E1E4E8\">)</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (fa[a][k] </span><span style=\"color:#F97583\">!=</span><span style=\"color:#E1E4E8\"> fa[b][k]) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            a </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> fa[a][k];</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            b </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> fa[b][k];</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    return</span><span style=\"color:#E1E4E8\"> fa[a][</span><span style=\"color:#79B8FF\">0</span><span style=\"color:#E1E4E8\">];</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>\n<h3 id=\"45-拓扑排序-topological-sort\">4.5 拓扑排序 (Topological Sort)</h3>\n<p><strong>问题</strong>：排课表。必须先修 A 才能修 B。</p>\n<p><strong>核心思想</strong>：入度为 0 的点入队，删边，更新邻居入度。</p>\n<pre class=\"astro-code github-dark\" style=\"background-color:#24292e;color:#e1e4e8; overflow-x: auto;\" tabindex=\"0\" data-language=\"cpp\"><code><span class=\"line\"><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> in_degree[N];</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">void</span><span style=\"color:#B392F0\"> topo_sort</span><span style=\"color:#E1E4E8\">(</span><span style=\"color:#F97583\">int</span><span style=\"color:#FFAB70\"> n</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    queue</span><span style=\"color:#F97583\">&#x3C;int></span><span style=\"color:#E1E4E8\"> q;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">    for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">int</span><span style=\"color:#E1E4E8\"> i </span><span style=\"color:#F97583\">=</span><span style=\"color:#79B8FF\"> 1</span><span style=\"color:#E1E4E8\">; i </span><span style=\"color:#F97583\">&#x3C;=</span><span style=\"color:#E1E4E8\"> n; i</span><span style=\"color:#F97583\">++</span><span style=\"color:#E1E4E8\">) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        if</span><span style=\"color:#E1E4E8\"> (in_degree[i] </span><span style=\"color:#F97583\">==</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">) q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(i);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">    while</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">!</span><span style=\"color:#E1E4E8\">q.</span><span style=\"color:#B392F0\">empty</span><span style=\"color:#E1E4E8\">()) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">        int</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> q.</span><span style=\"color:#B392F0\">front</span><span style=\"color:#E1E4E8\">(); q.</span><span style=\"color:#B392F0\">pop</span><span style=\"color:#E1E4E8\">();</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        cout </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#E1E4E8\"> u </span><span style=\"color:#F97583\">&#x3C;&#x3C;</span><span style=\"color:#9ECBFF\"> \" \"</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"></span>\n<span class=\"line\"><span style=\"color:#F97583\">        for</span><span style=\"color:#E1E4E8\"> (</span><span style=\"color:#F97583\">auto&#x26;</span><span style=\"color:#E1E4E8\"> edge : adj[u]) {</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            int</span><span style=\"color:#E1E4E8\"> v </span><span style=\"color:#F97583\">=</span><span style=\"color:#E1E4E8\"> edge.to;</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">            in_degree[v]</span><span style=\"color:#F97583\">--</span><span style=\"color:#E1E4E8\">;</span></span>\n<span class=\"line\"><span style=\"color:#F97583\">            if</span><span style=\"color:#E1E4E8\"> (in_degree[v] </span><span style=\"color:#F97583\">==</span><span style=\"color:#79B8FF\"> 0</span><span style=\"color:#E1E4E8\">) q.</span><span style=\"color:#B392F0\">push</span><span style=\"color:#E1E4E8\">(v);</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">        }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">    }</span></span>\n<span class=\"line\"><span style=\"color:#E1E4E8\">}</span></span>\n<span class=\"line\"></span></code></pre>";

				const frontmatter = {"title":"图论算法完全指南","description":"从邻接矩阵到最短路径，从 DFS 到最小生成树。本文结合 ACM 竞赛实战，深入解析图论的核心算法与数据结构实现。","publishedAt":"2025-12-21T09:00:00","category":"tech"};
				const file = "C:/Code/X_blog/src/content/posts/acm-graph-theory-mastery.md";
				const url = undefined;
				function rawContent() {
					return "\n图（Graph）是计算机科学中最强大、最复杂，也是 ACM/ICPC 竞赛中考察频率最高的数据结构之一。无论是社交网络的好友推荐，还是地图导航的最短路径，背后都离不开图论的支持。\n\n本文将用最通俗易懂的语言，带你系统梳理图论的核心知识体系。\n\n## 1. 图的基本概念：到底什么是图？\n\n别被“图论”这个高大上的名字吓到了。**图**其实就是用来描述“**关系**”的。\n\n想象一下微信好友列表：\n\n- **顶点 (Vertex)**：就是你和你的朋友们。\n- **边 (Edge)**：就是你们之间的“好友关系”。\n\n我们可以把图看作是从 **链表**（一条线）和 **树**（分叉的树枝）拓展而来的更自由的**网络**。\n\n### 常见的分类\n\n1.  **无向图 vs 有向图**：\n\n    - **无向图**：双向奔赴。比如微信好友，我加了你，你也就加了我。A 和 B 是平等的。\n    - **有向图**：单相思。比如微博关注，我关注了明星，明星不一定关注我。箭头是有方向的 (A -> B)。\n\n2.  **无权图 vs 有权图**：\n\n    - **有权图**：关系有“分量”。比如地图上两个城市之间，不仅连通，还有**距离**（权重）。或者两个人之间不仅认识，还有**亲密度**（权重）。\n\n3.  **连通图 vs 非连通图**：\n    - **连通图**：从任何一个点出发，都能走到其他任何一个点。\n    - **非连通图**：像几座孤岛，岛与岛之间没有桥。\n\n### 核心术语\n\n- **度 (Degree)**：一个点连了几条线。\n  - 在有向图中，**入度**是谁指向我，**出度**是我指向谁。\n- **路径 (Path)**：从起点走到终点经过的路线。\n\n---\n\n## 2. 图的存储：怎么把图塞进代码里？\n\n在 ACM 竞赛中，选对存图方式至关重要。选错了，要么代码写死人，要么内存爆掉。\n\n### 2.1 邻接矩阵 (Adjacency Matrix) —— 简单粗暴的二维数组\n\n想象一个表格，行是起点，列是终点。表格里的数字表示有没有边（或者权重）。\n\n- **特点**：简单直观。`g[i][j] = 1` 表示 i 和 j 连通。\n- **优点**：查得快！想知道 i 和 j 连不连？直接看表格。\n- **缺点**：太费地儿！如果有 10000 个点，就要开 `10000 * 10000` 的数组，内存直接爆炸。\n- **适用**：点很少的图（点数 N <= 1000）。\n\n```cpp\n// C++ 邻接矩阵示例\nconst int INF = 0x3f3f3f3f;\nint g[1005][1005];\n\nvoid init() {\n    // 刚开始谁都不挨着谁\n    memset(g, 0x3f, sizeof(g));\n}\n\nvoid add_edge(int u, int v, int w) {\n    g[u][v] = w;\n    g[v][u] = w; // 无向图记得反过来也要存一下\n}\n```\n\n### 2.2 邻接表 (Adjacency List) —— 也就是 Vector\n\n每个点都有一个小本本（Vector），上面记着它连着谁。\n\n- **特点**：按需分配。只存存在的边，省内存。\n- **优点**：空间利用率高，大部分题目都用它。\n- **缺点**：想知道 i 和 j 连不连？得翻 i 的小本本，稍微慢一点点。\n\n```cpp\n// C++ vector 实现邻接表\nstruct Edge {\n    int to;     // 连到谁\n    int weight; // 权重多少\n};\nvector<Edge> adj[100005]; // 每个点都有一个 vector\n\nvoid add_edge(int u, int v, int w) {\n    adj[u].push_back({v, w});\n    // 无向图加上这一句: adj[v].push_back({u, w});\n}\n```\n\n### 2.3 链式前向星 (Chain Forward Star) —— 数组模拟链表（高手必备）\n\n这是 ACM 选手最爱用的存图方式，虽然名字听起来很中二，但效率极高！\n\n它的本质是**用数组来模拟链表**。为什么不用 Vector？因为 Vector 动态扩容有点慢，而数组是静态的，快！\n\n**想象一下：**\n你要寄信（边）。\n\n- `head[u]`：你（点 u）寄出的**第一封信**的编号。\n- `next[e]`：信 e 下面压着的**下一封信**的编号。\n- `to[e]`：信 e 是寄给谁的。\n- `val[e]`：信 e 的权重。\n\n**插入边的时候（头插法）：**\n每次有新边，都把它插到最前面，变成新的“第一封信”，然后让它指向原来的“第一封信”。\n\n```cpp\n// 链式前向星模板\nconst int N = 100005;  // 最大点数\nconst int M = 200005;  // 最大边数\n\nint head[N]; // 存储每个点的第一条边的索引，初始化为 -1\nstruct Edge {\n    int to;   // 这条边去哪\n    int next; // 下一条同起点的边在哪\n    int w;    // 权重\n} edges[M];   // 边集数组\n\nint cnt = 0; // 边的计数器\n\n// 初始化\nvoid init() {\n    memset(head, -1, sizeof(head));\n    cnt = 0;\n}\n\n// 加边函数：把 u -> v，权重 w 的边加入\nvoid add(int u, int v, int w) {\n    edges[cnt].to = v;\n    edges[cnt].w = w;\n    edges[cnt].next = head[u]; // 新边的下一条指向原本的第一条（头插法）\n    head[u] = cnt;             // 更新 u 的第一条边为当前新边\n    cnt++;\n}\n\n// 遍历 u 的所有出边\nvoid traverse(int u) {\n    // i = head[u] 开始，只要 i != -1 就继续，每次跳到 next[i]\n    for (int i = head[u]; i != -1; i = edges[i].next) {\n        int v = edges[i].to;\n        int w = edges[i].w;\n        // 这里处理边 (u, v)\n        cout << \"从 \" << u << \" 到 \" << v << \" 权重 \" << w << endl;\n    }\n}\n```\n\n**为什么叫“前向星”？** 因为它是从某个点出发，像星星的光芒一样向前（Forward）发散出去。虽然代码稍显复杂，但**速度最快**，**内存最省**，是打比赛的终极武器。\n\n---\n\n## 3. 图的遍历：怎么在图里溜达？\n\n有了图，我们得进去走走。\n\n### 3.1 深度优先搜索 (DFS) —— 钻牛角尖\n\n**口诀**：“不撞南墙不回头”。\n一条路走到黑，走不通了再退回来换条路走。\n\n**用途**：\n\n- 走迷宫（找能不能走通）。\n- 全排列（把所有可能性都试一遍）。\n\n```cpp\nbool vis[100005]; // 记录走没走过，防止转圈圈\n\nvoid dfs(int u) {\n    vis[u] = true; // 标记：我来过啦\n\n    // 遍历 u 的所有邻居\n    for (auto& edge : adj[u]) {\n        int v = edge.to;\n        if (!vis[v]) { // 如果邻居没去过\n            dfs(v);    // 接着往下钻\n        }\n    }\n}\n```\n\n### 3.2 广度优先搜索 (BFS) —— 地毯式搜索\n\n**口诀**：“层层递进”。\n先把离我最近的一圈全走完，再走第二圈。\n\n**用途**：\n\n- **找最短路径**（仅限边权为 1 的图）。比如游戏里找最近的怪。\n\n```cpp\nvoid bfs(int start) {\n    queue<int> q;\n    q.push(start);\n    vis[start] = true;\n\n    while (!q.empty()) {\n        int u = q.front(); q.pop(); // 取出队头\n\n        for (auto& edge : adj[u]) {\n            int v = edge.to;\n            if (!vis[v]) {\n                vis[v] = true; // 标记\n                q.push(v);     // 加入队列，以后再处理\n            }\n        }\n    }\n}\n```\n\n---\n\n## 4. 经典算法实战（伪代码）\n\n光说不练假把式。这里给出 ACM 竞赛中最常用的核心算法模板，**建议背诵全文**！\n\n### 4.1 最短路径算法\n\n#### (1) Dijkstra 算法 —— 正权图的最短路之王\n\n**适用**：没有负权边的图。\n\n**核心思想**：贪心。每次从未被标记的点中，找到距离起点最近的那个点 `u`，然后用 `u` 去更新它的邻居们。\n\n**生活比喻**：你想去学校，先看看离家最近的车站 A 有多远，到了 A 之后，再看看通过 A 去其他地方会不会更近。\n\n```cpp\n// 堆优化 Dijkstra (复杂度 O(E log E))\n// dis[i] 存储起点到 i 的最短距离\nint dis[N];\nbool vis[N];\n// 小根堆，自动按距离从小到大排序\npriority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;\n\nvoid dijkstra(int start) {\n    memset(dis, 0x3f, sizeof(dis)); // 初始化无穷大\n    dis[start] = 0;\n    pq.push({0, start}); // {距离, 点编号}\n\n    while (!pq.empty()) {\n        int u = pq.top().second; // 拿出距离最近的点\n        pq.pop();\n\n        if (vis[u]) continue; // 如果处理过了就跳过\n        vis[u] = true;\n\n        for (auto& edge : adj[u]) {\n            int v = edge.to;\n            int w = edge.w;\n            // 松弛操作：如果通过 u 走到 v 更近\n            if (dis[v] > dis[u] + w) {\n                dis[v] = dis[u] + w;\n                pq.push({dis[v], v});\n            }\n        }\n    }\n}\n```\n\n#### (2) SPFA 算法 —— 负权边的克星\n\n**适用**：存在负权边，但没有负环的图。\n\n**核心思想**：队列优化的 Bellman-Ford。只有当一个点的最短距离变小了，它才可能去更新它的邻居，所以把它加入队列。\n\n**注意**：在网格图或构造数据中容易退化成 `O(VE)`，比赛时慎用（除非有负权边）。\n\n```cpp\nbool in_queue[N]; // 记录是否在队列中\nvoid spfa(int start) {\n    memset(dis, 0x3f, sizeof(dis));\n    dis[start] = 0;\n    queue<int> q;\n    q.push(start);\n    in_queue[start] = true;\n\n    while (!q.empty()) {\n        int u = q.front(); q.pop();\n        in_queue[u] = false; // 出队\n\n        for (auto& edge : adj[u]) {\n            int v = edge.to;\n            int w = edge.w;\n            if (dis[v] > dis[u] + w) {\n                dis[v] = dis[u] + w;\n                // 如果 v 已经在队列里，就不用重复加了\n                if (!in_queue[v]) {\n                    q.push(v);\n                    in_queue[v] = true;\n                }\n            }\n        }\n    }\n}\n```\n\n#### (3) Floyd-Warshall 算法 —— 多源最短路\n\n**适用**：求任意两点间的最短路，点数 `N <= 300`。\n\n**核心思想**：动态规划。对于每一对 `(i, j)`，看看能不能找个中间商 `k`，使得 `i -> k -> j` 比直接 `i -> j` 更短。\n\n**记忆口诀**：**“中间商 k 在最外层”**。\n\n```cpp\n// dp[i][j] 表示 i 到 j 的最短距离\nvoid floyd(int n) {\n    // k 必须在最外层循环！\n    for (int k = 1; k <= n; k++) {\n        for (int i = 1; i <= n; i++) {\n            for (int j = 1; j <= n; j++) {\n                dp[i][j] = min(dp[i][j], dp[i][k] + dp[k][j]);\n            }\n        }\n    }\n}\n```\n\n### 4.2 最小生成树 (MST)\n\n#### (1) Kruskal 算法 —— 加边法\n\n**适用**：稀疏图（边少）。\n\n**核心思想**：贪心。把所有路按造价从小到大排序，选最便宜且不构成环的路（用并查集维护）。\n\n```cpp\nstruct Edge { int u, v, w; };\nbool cmp(Edge a, Edge b) { return a.w < b.w; } // 按权重排序\nint fa[N];\nint find(int x) { return fa[x] == x ? x : fa[x] = find(fa[x]); }\n\nvoid kruskal(int n, vector<Edge>& edges) {\n    sort(edges.begin(), edges.end(), cmp);\n    for (int i = 1; i <= n; i++) fa[i] = i;\n\n    int count = 0, total_weight = 0;\n    for (auto& e : edges) {\n        int root_u = find(e.u);\n        int root_v = find(e.v);\n        if (root_u != root_v) {\n            fa[root_u] = root_v;\n            total_weight += e.w;\n            count++;\n            if (count == n - 1) break;\n        }\n    }\n}\n```\n\n#### (2) Prim 算法 —— 加点法\n\n**适用**：稠密图（边多）。\n\n**核心思想**：类似 Dijkstra。每次寻找距离“当前生成树”最近的那个点，把它加入集合。\n\n```cpp\nint dist[N]; // 点到生成树的最小距离\nbool vis[N]; // 是否已加入生成树\n\nint prim(int n) {\n    memset(dist, 0x3f, sizeof(dist));\n    int res = 0;\n    dist[1] = 0; // 从点 1 开始\n\n    for (int i = 0; i < n; i++) {\n        int t = -1;\n        // 寻找离集合最近的点\n        for (int j = 1; j <= n; j++) {\n            if (!vis[j] && (t == -1 || dist[j] < dist[t]))\n                t = j;\n        }\n\n        if (i && dist[t] == INF) return INF; // 图不连通\n        if (i) res += dist[t];\n        vis[t] = true;\n\n        // 用这个新点去更新其他点到集合的距离\n        for (int j = 1; j <= n; j++)\n            dist[j] = min(dist[j], g[t][j]); // g 是邻接矩阵\n    }\n    return res;\n}\n```\n\n### 4.3 图的连通性\n\n#### Tarjan 算法 —— 强连通分量 (SCC)\n\n**适用**：有向图缩点。\n\n**核心思想**：DFS 序 + 追溯值。如果一个点走了一圈能回到自己（或祖先），说明有个环。\n\n```cpp\nint dfn[N], low[N], timestamp;\nstack<int> stk;\nbool in_stk[N];\nint scc_cnt, id[N]; // 强连通分量编号\n\nvoid tarjan(int u) {\n    dfn[u] = low[u] = ++timestamp;\n    stk.push(u); in_stk[u] = true;\n\n    for (int v : adj[u]) {\n        if (!dfn[v]) {\n            tarjan(v);\n            low[u] = min(low[u], low[v]);\n        } else if (in_stk[v]) {\n            low[u] = min(low[u], dfn[v]);\n        }\n    }\n\n    // 找到一个 SCC 的根\n    if (dfn[u] == low[u]) {\n        scc_cnt++;\n        int y;\n        do {\n            y = stk.top(); stk.pop();\n            in_stk[y] = false;\n            id[y] = scc_cnt;\n        } while (y != u);\n    }\n}\n```\n\n### 4.4 最近公共祖先 (LCA)\n\n#### 倍增法\n\n**核心思想**：预处理出每个节点的第 $2^i$ 个祖先。查询时，先让深度深的跳到同一层，然后一起向上跳。\n\n```cpp\nint fa[N][20], depth[N]; // fa[u][i] 表示 u 向上跳 2^i 步的祖先\n\nvoid bfs_lca(int root) {\n    memset(depth, 0x3f, sizeof(depth));\n    depth[0] = 0; depth[root] = 1;\n    queue<int> q; q.push(root);\n\n    while (q.size()) {\n        int u = q.front(); q.pop();\n        for (int v : adj[u]) {\n            if (depth[v] > depth[u] + 1) {\n                depth[v] = depth[u] + 1;\n                q.push(v);\n                fa[v][0] = u; // 跳 2^0 = 1 步就是父节点\n                for (int k = 1; k <= 15; k++)\n                    fa[v][k] = fa[fa[v][k-1]][k-1]; // 2^k = 2^(k-1) + 2^(k-1)\n            }\n        }\n    }\n}\n\nint lca(int a, int b) {\n    if (depth[a] < depth[b]) swap(a, b);\n    // 先把 a 跳到和 b 同一层\n    for (int k = 15; k >= 0; k--)\n        if (depth[fa[a][k]] >= depth[b])\n            a = fa[a][k];\n    if (a == b) return a;\n    // 一起向上跳，直到父亲相同\n    for (int k = 15; k >= 0; k--)\n        if (fa[a][k] != fa[b][k]) {\n            a = fa[a][k];\n            b = fa[b][k];\n        }\n    return fa[a][0];\n}\n```\n\n### 4.5 拓扑排序 (Topological Sort)\n\n**问题**：排课表。必须先修 A 才能修 B。\n\n**核心思想**：入度为 0 的点入队，删边，更新邻居入度。\n\n```cpp\nint in_degree[N];\n\nvoid topo_sort(int n) {\n    queue<int> q;\n    for (int i = 1; i <= n; i++) {\n        if (in_degree[i] == 0) q.push(i);\n    }\n\n    while (!q.empty()) {\n        int u = q.front(); q.pop();\n        cout << u << \" \";\n\n        for (auto& edge : adj[u]) {\n            int v = edge.to;\n            in_degree[v]--;\n            if (in_degree[v] == 0) q.push(v);\n        }\n    }\n}\n```\n";
				}
